create table awh_main.awh_erhebungsbogen_5 (
    eb5_lfd_nr            number default to_number(sys_guid(), 'XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX'),
    asy_lfd_nr            number not null enable,
    eb5_internestelle_dwi varchar2(1000 byte),
    eb5_artdaten_dwi      varchar2(1000 byte),
    eb5_zweck_dwi         varchar2(1000 byte),
    eb5_externestelle_dwe varchar2(1000 byte),
    eb5_artdaten_dwe      varchar2(1000 byte),
    eb5_zweck_dwe         varchar2(1000 byte),
    eb5_staat_dws         varchar2(1000 byte),
    eb5_artdaten_dws      varchar2(1000 byte),
    eb5_zweck_dws         varchar2(1000 byte),
    eb5_timestamp         timestamp(6) not null enable,
    eb5_user              varchar2(100 byte)
)
no inmemory;

alter table awh_main.awh_erhebungsbogen_5
    add constraint awh_erhebungsbogen_5_pk primary key ( eb5_lfd_nr )
        using index enable;


